import create from 'zustand';
export const useStore = create(set => ({
  openChats: [],
  // [{id, user, zIndex}]
  nextZ: 100,
  contacts: [],
  setContacts: c => set({
    contacts: c
  }),
  openChat: chat => set(state => ({
    openChats: [...state.openChats, {
      ...chat,
      zIndex: state.nextZ
    }],
    nextZ: state.nextZ + 1
  })),
  focusChat: id => set(state => ({
    openChats: state.openChats.map(c => c.id === id ? {
      ...c,
      zIndex: state.nextZ
    } : c),
    nextZ: state.nextZ + 1
  })),
  closeChat: id => set(state => ({
    openChats: state.openChats.filter(c => c.id !== id)
  }))
}));
